"use client";

import { useState, useEffect, useMemo } from "react";
import { useParams } from "next/navigation";
import StatViewToggle from "@/components/stat-view-toggle";
import DataTable from "@/components/data-table";
import {
  playerDetailColumns,
  playerGameLogColumns,
  gameHighsColumns,
  categoryLeaderColumns,
  splitColumns,
} from "@/lib/columns";
import { fmtKr, fmtHeight } from "@/lib/stats";
import type {
  StatView,
  Player,
  PlayerSeasonTotals,
  PlayerGameStats,
  PlayerKR,
  GameHighRow,
  CategoryLeader,
  TeamSplitRow,
} from "@/lib/types";

type PlayerTab =
  | "overall"
  | "conference"
  | "nonConference"
  | "splits"
  | "gameLog"
  | "gameHighs"
  | "leaders"
  | "kr";

const TABS: { key: PlayerTab; label: string }[] = [
  { key: "overall", label: "Overall" },
  { key: "conference", label: "Conference" },
  { key: "nonConference", label: "Non-Conf" },
  { key: "splits", label: "Splits" },
  { key: "gameLog", label: "Game Log" },
  { key: "gameHighs", label: "Game Highs" },
  { key: "leaders", label: "Leaders" },
  { key: "kr", label: "KR" },
];

export default function PlayerDetailPage() {
  const params = useParams();
  const teamId = params.teamId as string;
  const playerId = params.playerId as string;

  const [tab, setTab] = useState<PlayerTab>("overall");
  const [statView, setStatView] = useState<StatView>("perGame");
  const [loading, setLoading] = useState(true);

  const [player, setPlayer] = useState<Player | null>(null);
  const [overall, setOverall] = useState<PlayerSeasonTotals | null>(null);
  const [conferenceStats, setConferenceStats] = useState<PlayerSeasonTotals | null>(null);
  const [nonConferenceStats, setNonConferenceStats] = useState<PlayerSeasonTotals | null>(null);
  const [splits, setSplits] = useState<TeamSplitRow[]>([]);
  const [gameLog, setGameLog] = useState<PlayerGameStats[]>([]);
  const [gameHighs, setGameHighs] = useState<GameHighRow[]>([]);
  const [categoryLeaders, setCategoryLeaders] = useState<CategoryLeader[]>([]);
  const [kr, setKr] = useState<PlayerKR | null>(null);

  useEffect(() => {
    fetch(`/api/teams/${teamId}/players/${playerId}`)
      .then((r) => r.json())
      .then((data) => {
        setPlayer(data.player);
        setOverall(data.overall ?? null);
        setConferenceStats(data.conferenceStats ?? null);
        setNonConferenceStats(data.nonConferenceStats ?? null);
        setSplits(data.splits ?? []);
        setGameLog(data.gameLog ?? []);
        setGameHighs(data.gameHighs ?? []);
        setCategoryLeaders(data.categoryLeaders ?? []);
        setKr(data.kr ?? null);
        setLoading(false);
      });
  }, [teamId, playerId]);

  const detailCols = useMemo(() => playerDetailColumns(statView), [statView]);
  const gameLogCols = useMemo(() => playerGameLogColumns(), []);
  const gameHighCols = useMemo(() => gameHighsColumns(), []);
  const leaderCols = useMemo(() => categoryLeaderColumns(), []);

  // Reuse splitColumns for player splits (same shape)
  const splitCols = useMemo(() => splitColumns(), []);
  const splitData: TeamSplitRow[] = useMemo(
    () =>
      splits.map((s) => ({
        ...s,
        oppPpg: s.oppPpg ?? 0,
      })),
    [splits]
  );

  if (loading) {
    return <div className="text-center py-12 text-slate-400">Loading...</div>;
  }

  if (!player) {
    return <div className="text-center py-12 text-slate-400">Player not found</div>;
  }

  const showStatToggle = tab === "overall" || tab === "conference" || tab === "nonConference";

  const statData: PlayerSeasonTotals | null =
    tab === "overall"
      ? overall
      : tab === "conference"
      ? conferenceStats
      : tab === "nonConference"
      ? nonConferenceStats
      : null;

  return (
    <>
      {/* Header */}
      <div className="mb-4">
        <h1 className="text-2xl font-bold tracking-tight">{player.name}</h1>
        <p className="text-sm text-slate-500">
          {player.teamName} &middot; {player.level} &middot; {player.conference}
          {player.position && ` \u00b7 ${player.position}`}
          {player.heightInches && ` \u00b7 ${fmtHeight(player.heightInches)}`}
          {player.classYear && ` \u00b7 ${player.classYear}`}
        </p>
      </div>

      {/* Tabs */}
      <div className="flex items-center gap-1 border-b border-slate-200 mb-4 overflow-x-auto">
        {TABS.map((t) => (
          <button
            key={t.key}
            onClick={() => setTab(t.key)}
            className={`px-3 py-2 text-sm font-medium border-b-2 transition-colors whitespace-nowrap ${
              tab === t.key
                ? "border-slate-900 text-slate-900"
                : "border-transparent text-slate-400 hover:text-slate-600"
            }`}
          >
            {t.label}
          </button>
        ))}
      </div>

      {/* Overall / Conference / Non-Conference tabs */}
      {showStatToggle && (
        <>
          <div className="flex items-center justify-end mb-4">
            <StatViewToggle value={statView} onChange={setStatView} />
          </div>
          {statData && <DataTable columns={detailCols} data={[statData]} />}
        </>
      )}

      {/* Splits tab */}
      {tab === "splits" && <DataTable columns={splitCols} data={splitData} />}

      {/* Game Log tab */}
      {tab === "gameLog" && (
        <DataTable
          columns={gameLogCols}
          data={gameLog}
          defaultSortKey="date"
          defaultSortDir="desc"
        />
      )}

      {/* Game Highs tab */}
      {tab === "gameHighs" && <DataTable columns={gameHighCols} data={gameHighs} />}

      {/* Leaders tab */}
      {tab === "leaders" && (
        <>
          {categoryLeaders.length > 0 ? (
            <DataTable columns={leaderCols} data={categoryLeaders} />
          ) : (
            <div className="text-center py-12 text-slate-400">
              Not ranked in top 3 for any category
            </div>
          )}
        </>
      )}

      {/* KR tab */}
      {tab === "kr" && kr && (
        <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-4">
          {[
            { label: "Overall KR", value: kr.kr },
            { label: "Offensive KR", value: kr.krOff },
            { label: "Defensive KR", value: kr.krDef },
            { label: "Shooting", value: kr.krShooting },
            { label: "Finishing", value: kr.krFinishing },
            { label: "Playmaking", value: kr.krPlaymaking },
            { label: "POA Defense", value: kr.krPoaDefense },
            { label: "Team Defense", value: kr.krTeamDefense },
            { label: "Rebounding", value: kr.krRebounding },
            { label: "Tools", value: kr.krTools },
            { label: "IQ", value: kr.krIq },
          ].map((item) => (
            <div
              key={item.label}
              className="bg-white border border-slate-200 rounded-lg p-4 text-center"
            >
              <div className="text-xs font-medium text-slate-500 uppercase tracking-wide mb-1">
                {item.label}
              </div>
              <div className="text-2xl font-bold text-slate-900">
                {fmtKr(item.value)}
              </div>
            </div>
          ))}
        </div>
      )}
    </>
  );
}
