import type { StatView } from "./types";

export const LEVEL_LABELS: Record<string, string> = {
  ncaa_d1: "NCAA D1",
  ncaa_d2: "NCAA D2",
  ncaa_d3: "NCAA D3",
  naia: "NAIA",
  njcaa_d1: "NJCAA D1",
  njcaa_d2: "NJCAA D2",
  njcaa_d3: "NJCAA D3",
  cccaa: "CCCAA",
};

export const LEVEL_KEYS = Object.keys(LEVEL_LABELS);

/** Format a number as integer */
export function fmtInt(n: number | null | undefined): string {
  if (n == null) return "";
  return Math.round(n).toString();
}

/** Format a number with one decimal */
export function fmtDec(n: number | null | undefined): string {
  if (n == null) return "";
  return n.toFixed(1);
}

/** Format a ratio as percentage with one decimal (e.g. 37.8%) */
export function fmtPct(
  num: number | null | undefined,
  den: number | null | undefined
): string {
  if (num == null || den == null || den === 0) return "";
  return ((num / den) * 100).toFixed(1) + "%";
}

/** Compute per-game value */
export function perGame(
  val: number | null | undefined,
  gp: number
): number | null {
  if (val == null || gp === 0) return null;
  return val / gp;
}

/** Compute per-40 value */
export function per40(
  val: number | null | undefined,
  min: number
): number | null {
  if (val == null || min === 0) return null;
  return (val / min) * 40;
}

/** Format a counting stat based on stat view */
export function fmtStat(
  val: number | null | undefined,
  view: StatView,
  gp: number,
  min: number
): string {
  if (val == null) return "";
  switch (view) {
    case "totals":
      return fmtInt(val);
    case "perGame":
      return fmtDec(perGame(val, gp));
    case "per40":
      return fmtDec(per40(val, min));
  }
}

/** Format height from inches to display string (e.g. 6'3") */
export function fmtHeight(inches: number | null | undefined): string {
  if (inches == null) return "";
  const ft = Math.floor(inches / 12);
  const rem = inches % 12;
  return `${ft}'${rem}"`;
}

/** Compute eFG% */
export function efgPct(fgm: number, threePm: number, fga: number): string {
  if (fga === 0) return "";
  return (((fgm + 0.5 * threePm) / fga) * 100).toFixed(1) + "%";
}

/** Compute TS% */
export function tsPct(pts: number, fga: number, fta: number): string {
  const den = 2 * (fga + 0.44 * fta);
  if (den === 0) return "";
  return ((pts / den) * 100).toFixed(1) + "%";
}

/** Compute AST/TO */
export function astTo(ast: number, to: number): string {
  if (to === 0) return "";
  return (ast / to).toFixed(1);
}

/** Format a KR value */
export function fmtKr(val: number | null | undefined): string {
  if (val == null) return "--";
  return val.toFixed(1);
}
